div.script:
(function () {
  fetch('https://a7-346215327.cluster327.canvas-user-content.com/courses/7~14409101/files/7~346215327/course%20files/singlefile.html')
    .then(function (r) { return r.text(); })
    .then(function (data) {
      var fm = document.getElementById('fm');

      // Safer way to inject content
      var doc = fm.contentWindow.document;
      doc.open();
      doc.write(data);
      doc.close();
    })
    .catch(function (e) {
      console.error('Failed to load content:', e);
    });
})();
